-- SEVERITY: high  EXPECTED: 0
-- Direct attribute comparison for EXG_DIM_ID between target and control tables.
-- target_query: (none -- single-source test)

SELECT /*+ PARALLEL(32) */ COUNT(*) AS mismatch_count
FROM TRANSACTIONS_OWNER.AVY_FACT_SIDE T
JOIN IKOROSTELEV.AVY_FACT_SIDE CTL
